cadishfile:
example.com {
    @html content_type text/html
    @media path /media/*
    edge {
        worker  cadish-edge-example
        kv      EDGE_CACHE
        default local
        distribute @html
        skip @media
        kv_ttl       5m
        kv_max_bytes 256KiB
    }
    cache_key url
    cache_ttl default ttl 30s grace 1h
    header +cache_status X-Cache
}
